// Application layer
public class PlaceOrderHandler
{
    private readonly IOrderRepository _orders;
    private readonly IInventoryRepository _inventory;
    private readonly IUnitOfWork _uow;

    public async Task HandleAsync(PlaceOrderCommand cmd, CancellationToken ct)
    {
        var order = Order.Create(cmd.CustomerId, cmd.Items);
        var item = await _inventory.GetAsync(cmd.Items[0].ProductId, ct);
        item.Reserve(cmd.Items[0].Quantity);

        await _orders.AddAsync(order, ct);
        // Both changes commit atomically:
        await _uow.CommitAsync(ct);
    }
}

// Handler — write side (Command)
public class PlaceOrderHandler : IRequestHandler<PlaceOrderCommand, Guid>
{
    private readonly IOrderRepository _repo;
    private readonly IUnitOfWork _uow;
    public PlaceOrderHandler(IOrderRepository repo, IUnitOfWork uow)
        => (_repo, _uow) = (repo, uow);

    public async Task<Guid> Handle(PlaceOrderCommand cmd, CancellationToken ct)
    {
        var order = Order.Create(cmd.CustomerId, cmd.Items);
        await _repo.AddAsync(order, ct);
        await _uow.CommitAsync(ct);
        return order.Id;
    }
}

// Handler — read side (Query) — skips domain layer, hits DB directly
public class GetOrderSummaryHandler : IRequestHandler<GetOrderSummaryQuery, OrderSummaryDto>
{
    private readonly AppDbContext _db;
    public GetOrderSummaryHandler(AppDbContext db) => _db = db;

    public Task<OrderSummaryDto> Handle(GetOrderSummaryQuery q, CancellationToken ct)
        => _db.Orders
              .AsNoTracking()
              .Where(o => o.Id == q.OrderId)
              .Select(o => new OrderSummaryDto(o.Id, o.Status, o.TotalAmount))
              .FirstOrDefaultAsync(ct)!;
}

// .NET 8 — Microsoft.Extensions.Http.Resilience
builder.Services.AddHttpClient<IPaymentClient, PaymentClient>()
    .AddResilienceHandler("payment", pipeline =>
    {
        pipeline.AddRetry(new HttpRetryStrategyOptions
        {
            MaxRetryAttempts = 3,
            BackoffType = DelayBackoffType.Exponential,
            UseJitter = true,
            ShouldHandle = args => ValueTask.FromResult(
                args.Outcome.Result?.StatusCode is
                    HttpStatusCode.ServiceUnavailable or
                    HttpStatusCode.TooManyRequests)
        });
        pipeline.AddCircuitBreaker(new HttpCircuitBreakerStrategyOptions
        {
            BreakDuration = TimeSpan.FromSeconds(30)
        });
        pipeline.AddTimeout(TimeSpan.FromSeconds(5));
    });

