// 1. Request + Handler
public record GetProductQuery(Guid Id) : IRequest<ProductDto>;

public class GetProductHandler : IRequestHandler<GetProductQuery, ProductDto>
{
    private readonly IProductRepository _repo;
    public GetProductHandler(IProductRepository repo) => _repo = repo;

    public async Task<ProductDto> Handle(GetProductQuery q, CancellationToken ct)
    {
        var product = await _repo.GetByIdAsync(q.Id, ct);
        return product is null
            ? throw new NotFoundException(nameof(Product), q.Id)
            : new ProductDto(product.Id, product.Name, product.Price);
    }
}

