public class Order : AggregateRoot  // AggregateRoot is a base class that holds domain events
{
    private readonly List<OrderLine> _lines = new();
    public IReadOnlyList<OrderLine> Lines => _lines.AsReadOnly();
    public OrderStatus Status { get; private set; } = OrderStatus.Draft;

    public void AddLine(ProductId productId, int quantity, Money unitPrice)
    {
        if (Status != OrderStatus.Draft)
            throw new InvalidOperationException("Cannot modify a confirmed order.");
        _lines.Add(new OrderLine(productId, quantity, unitPrice));
    }

    public void Confirm()
    {
        if (!_lines.Any()) throw new DomainException("Order must have at least one line.");
        Status = OrderStatus.Confirmed;
        RaiseDomainEvent(new OrderConfirmedEvent(Id, DateTime.UtcNow));
    }
}

// Redis-backed idempotency middleware sketch
public async Task InvokeAsync(HttpContext ctx, IDistributedCache cache)
{
    if (!ctx.Request.Headers.TryGetValue("Idempotency-Key", out var key))
    {
        await _next(ctx);
        return;
    }

    var cached = await cache.GetStringAsync(key!);
    if (cached is not null)
    {
        ctx.Response.ContentType = "application/json";
        ctx.Response.StatusCode = 200;
        await ctx.Response.WriteAsync(cached);
        return;
    }

    // Capture response body for storage
    var originalBody = ctx.Response.Body;
    using var ms = new MemoryStream();
    ctx.Response.Body = ms;
    await _next(ctx);

    ms.Seek(0, SeekOrigin.Begin);
    var body = await new StreamReader(ms).ReadToEndAsync();
    await cache.SetStringAsync(key!, body,
        new DistributedCacheEntryOptions { AbsoluteExpirationRelativeToNow = TimeSpan.FromHours(24) });

    ms.Seek(0, SeekOrigin.Begin);
    await ms.CopyToAsync(originalBody);
}

public async Task<ProductDto?> GetProductAsync(Guid id, CancellationToken ct)
{
    var cacheKey = $"product:{id}";
    if (!_cache.TryGetValue(cacheKey, out ProductDto? product))
    {
        product = await _db.Products.AsNoTracking()
            .Where(p => p.Id == id)
            .Select(p => new ProductDto(p.Id, p.Name, p.Price))
            .FirstOrDefaultAsync(ct);

        if (product is not null)
            _cache.Set(cacheKey, product, TimeSpan.FromMinutes(10));
    }
    return product;
}

