services.AddDbContext<ReadDbContext>(options =>
    options.UseSqlServer(Configuration["ConnectionStrings:ReadReplica"]));

public class GetProductListHandler : IRequestHandler<GetProductListQuery, List<ProductDto>>
{
    private readonly ReadDbContext _db;
    public Task<List<ProductDto>> Handle(GetProductListQuery q, CancellationToken ct)
        => _db.Products.AsNoTracking()
              .Where(p => p.CategoryId == q.CategoryId && p.IsActive)
              .OrderBy(p => p.Price)
              .Select(p => new ProductDto(p.Id, p.Name, p.Price))
              .ToListAsync(ct);
}
